     1→import { useState, useRef, useEffect } from 'react';
     2→import { motion, AnimatePresence } from 'framer-motion';
     3→import { Link } from 'react-router-dom';
     4→import { useTranslation } from 'react-i18next';
     5→import { streamAIResponse, generateLogoImage, generateImage } from '../utils/api';
     6→import { useSubscription } from '../context/SubscriptionContext';
     7→import { useAuth } from '../context/AuthContext';
     8→import { collection, addDoc, getDocs, deleteDoc, doc, query, where, orderBy, serverTimestamp } from 'firebase/firestore';
     9→import { db } from '../firebase/config';
    10→import ReactMarkdown from 'react-markdown';
    11→import remarkGfm from 'remark-gfm';
    12→import './AIToolInterface.css';
