    14→function FormField({ field, value, onChange, toolId }) {
    15→  const { t } = useTranslation();
    16→  const label = t(`input.${toolId}.${field.id}.label`, { defaultValue: field.label });
    17→  const placeholder = t(`input.${toolId}.${field.id}.placeholder`, { defaultValue: field.placeholder || '' });
    18→
    19→  const commonProps = {
    20→    id: field.id,
    21→    value: value || '',
    22→    onChange: (e) => onChange(field.id, e.target.value),
    23→    placeholder,
    24→    required: field.required,
    25→  };
    26→
    27→  if (field.type === 'textarea') {
    28→    return (
    29→      <div className="form-group">
    30→        <label className="form-label" htmlFor={field.id}>
    31→          {label}
    32→          {field.required && <span className="required-mark"> *</span>}
    33→        </label>
    34→        <textarea className="form-textarea" rows={4} {...commonProps} />
    35→      </div>
    36→    );
    37→  }
    38→
    39→  if (field.type === 'select') {
    40→    return (
    41→      <div className="form-group">
    42→        <label className="form-label" htmlFor={field.id}>
    43→          {label}
    44→          {field.required && <span className="required-mark"> *</span>}
    45→        </label>
    46→        <select className="form-select" {...commonProps}>
    47→          <option value="">{t('ui.selectOption', { defaultValue: 'Select an option...' })}</option>
    48→          {field.options.map((opt) => (
    49→            <option key={opt} value={opt}>{opt}</option>
    50→          ))}
    51→        </select>
    52→      </div>
    53→    );
    54→  }
    55→
    56→  if (field.type === 'multiselect') {
    57→    const selected = value ? value.split(', ').filter(Boolean) : [];
    58→    return (
    59→      <div className="form-group">
    60→        <label className="form-label">
    61→          {label}
    62→          {field.required && <span className="required-mark"> *</span>}
    63→        </label>
    64→        <div className="form-multiselect">
    65→          {field.options.map((opt) => {
    66→            const checked = selected.includes(opt);
    67→            return (
    68→              <label key={opt} className={`form-multiselect__option${checked ? ' form-multiselect__option--checked' : ''}`}>
    69→                <input
    70→                  type="checkbox"
    71→                  checked={checked}
    72→                  onChange={(e) => {
    73→                    const next = e.target.checked
    74→                      ? [...selected, opt]
    75→                      : selected.filter((o) => o !== opt);
    76→                    onChange(field.id, next.join(', '));
    77→                  }}
    78→                />
    79→                <span>{opt}</span>
    80→              </label>
    81→            );
    82→          })}
    83→        </div>
    84→      </div>
    85→    );
    86→  }
    87→
    88→  return (
    89→    <div className="form-group">
    90→      <label className="form-label" htmlFor={field.id}>
    91→        {label}
    92→        {field.required && <span className="required-mark"> *</span>}
    93→      </label>
    94→      <input type="text" className="form-input" {...commonProps} />
    95→    </div>
    96→  );
    97→}
