    99→export default function AIToolInterface({ tool, categoryId }) {
   100→  const [inputs, setInputs] = useState({});
   101→  const [output, setOutput] = useState('');
   102→  const [isStreaming, setIsStreaming] = useState(false);
   103→  const [error, setError] = useState('');
   104→  const [copied, setCopied] = useState(false);
   105→  const [wordCount, setWordCount] = useState(0);
   106→  const outputRef = useRef(null);
   107→  const outputPanelRef = useRef(null);
   108→  const abortControllerRef = useRef(null);
   109→  const finalOutputRef = useRef('');
   110→  const [history, setHistory] = useState([]);
   111→  const [historyOpen, setHistoryOpen] = useState(false);
   112→  const [templates, setTemplates] = useState([]);
   113→  const [templatesOpen, setTemplatesOpen] = useState(false);
   114→  const [showSaveTemplate, setShowSaveTemplate] = useState(false);
   115→  const [templateName, setTemplateName] = useState('');
   116→  const [savingTemplate, setSavingTemplate] = useState(false);
   117→  const [generatedImage, setGeneratedImage] = useState(null);
   118→  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
   119→  const [imageError, setImageError] = useState('');
   120→
   121→  const { currentUser } = useAuth();
   122→  const { canUseSpecificTool, trackUsage, subscription } = useSubscription();
   123→  const { t, i18n } = useTranslation();
   124→
   125→  // Reset when tool changes
   126→  useEffect(() => {
   127→    const defaults = categoryId !== 'creative'
   128→      ? { _location: 'Vitoria-Gasteiz, Álava. España' }
   129→      : {};
   130→    setInputs(defaults);
   131→    setOutput('');
   132→    setError('');
   133→    setIsStreaming(false);
   134→    setGeneratedImage(null);
   135→    setImageError('');
   136→  }, [tool?.id, categoryId]);
   137→
   138→  // Load history when tool changes
   139→  useEffect(() => {
   140→    if (tool?.id) {
   141→      try {
   142→        const stored = localStorage.getItem(`gormaran_history_${tool.id}`);
   143→        setHistory(stored ? JSON.parse(stored) : []);
   144→      } catch {
   145→        setHistory([]);
   146→      }
   147→    }
   148→    setHistoryOpen(false);
   149→  }, [tool?.id]);
   150→
   151→  // Load Firestore templates when tool or user changes
   152→  useEffect(() => {
   153→    setTemplates([]);
   154→    setTemplatesOpen(false);
   155→    setShowSaveTemplate(false);
   156→    setTemplateName('');
   157→    if (tool?.id && currentUser) loadTemplates();
   158→  // eslint-disable-next-line react-hooks/exhaustive-deps
   159→  }, [tool?.id, currentUser?.uid]);
   160→
   161→  // Track word count
   162→  useEffect(() => {
   163→    if (output) {
   164→      setWordCount(output.split(/\s+/).filter(Boolean).length);
   165→    } else {
   166→      setWordCount(0);
   167→    }
   168→  }, [output]);
   169→
   170→  // Auto-scroll output
   171→  useEffect(() => {
   172→    if (outputRef.current && isStreaming) {
   173→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
   174→    }
   175→  }, [output, isStreaming]);
   176→
   177→  function handleInputChange(fieldId, value) {
   178→    setInputs((prev) => ({ ...prev, [fieldId]: value }));
   179→  }
   180→
   181→  function validateInputs() {
   182→    const required = tool.inputs.filter((f) => f.required);
   183→    for (const field of required) {
   184→      if (!inputs[field.id] || inputs[field.id].trim() === '') {
   185→        const fieldLabel = t(`input.${tool.id}.${field.id}.label`, { defaultValue: field.label });
   186→        return `"${fieldLabel}" is required`;
   187→      }
   188→    }
   189→    return null;
   190→  }
   191→
   192→  async function handleGenerate(e) {
   193→    e.preventDefault();
   194→    setError('');
   195→
   196→    if (!currentUser) {
   197→      setError(t('ui.signInRequired', { defaultValue: 'Please sign in or create a free account to use this tool.' }));
   198→      return;
   199→    }
   200→
   201→    if (!canUseSpecificTool(categoryId, tool.id)) {
   202→      setError(t('ui.upgradeRequired', { defaultValue: 'This tool requires an upgrade. Visit the pricing page to see your options.' }));
   203→      return;
   204→    }
   205→
   206→    const validationError = validateInputs();
   207→    if (validationError) {
   208→      setError(validationError);
   209→      return;
   210→    }
   211→
   212→    // imageOnly tools skip text streaming and go straight to image generation
   213→    if (tool.imageOnly) {
   214→      setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   215→      handleGenerateImage();
   216→      return;
   217→    }
   218→
   219→    setOutput('');
   220→    finalOutputRef.current = '';
   221→    setIsStreaming(true);
   222→    const controller = new AbortController();
   223→    abortControllerRef.current = controller;
   224→    setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   225→    const capturedInputs = { ...inputs };
   226→
   227→    await streamAIResponse({
   228→      categoryId,
   229→      toolId: tool.id,
   230→      inputs: { ...inputs, _language: i18n.language },
   231→      signal: controller.signal,
   232→      onChunk: (text) => {
   233→        setOutput((prev) => {
   234→          const next = prev + text;
   235→          finalOutputRef.current = next;
   236→          return next;
   237→        });
   238→      },
   239→      onDone: () => {
   240→        setIsStreaming(false);
   241→        trackUsage();
   242→        saveToHistory(capturedInputs, finalOutputRef.current);
   243→      },
   244→      onError: (msg) => {
   245→        setIsStreaming(false);
   246→        setError(msg);
   247→      },
   248→    });
   249→  }
   250→
   251→  function handleStop() {
   252→    abortControllerRef.current?.abort();
   253→    setIsStreaming(false);
   254→  }
   255→
   256→  async function handleGenerateImage() {
   257→    setImageError('');
   258→    setGeneratedImage(null);
   259→    setIsGeneratingImage(true);
   260→    try {
   261→      const apiFn = tool.imageEndpoint === 'generate' ? generateImage : generateLogoImage;
   262→      const { imageUrl } = await apiFn({ ...inputs, _language: i18n.language });
   263→      setGeneratedImage(imageUrl);
   264→    } catch (err) {
   265→      setImageError(err.message || 'Failed to generate image');
   266→    } finally {
   267→      setIsGeneratingImage(false);
   268→    }
   269→  }
   270→
   271→  function stripMarkdown(text) {
   272→    return text
   273→      .replace(/```[\w]*\n?([\s\S]*?)```/g, '$1')
   274→      .replace(/`([^`]+)`/g, '$1')
   275→      .replace(/^#{1,6}\s+/gm, '')
   276→      .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
   277→      .replace(/_{1,3}([^_\n]+)_{1,3}/g, '$1')
   278→      .replace(/~~([^~]+)~~/g, '$1')
   279→      .replace(/!\[([^\]]*)\]\([^)]+\)/g, '')
   280→      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
   281→      .replace(/^>\s+/gm, '')
   282→      .replace(/^[-*_]{3,}\s*$/gm, '')
   283→      .replace(/^\|[-| :]+\|$/gm, '')
   284→      .replace(/^\|(.+)\|$/gm, (_, cells) =>
   285→        cells.split('|').map(c => c.trim()).filter(Boolean).join('  '))
   286→      .replace(/\n{3,}/g, '\n\n')
   287→      .trim();
   288→  }
   289→
   290→  async function handleCopy() {
   291→    if (!output) return;
   292→    await navigator.clipboard.writeText(stripMarkdown(output));
   293→    setCopied(true);
   294→    setTimeout(() => setCopied(false), 2000);
   295→  }
   296→
   297→  function handleClear() {
   298→    setOutput('');
   299→    setError('');
   300→    setInputs({});
   301→    finalOutputRef.current = '';
   302→  }
   303→
   304→  function extractJson(text) {
   305→    const match = text.match(/```json\s*([\s\S]*?)```/);
   306→    return match ? match[1].trim() : null;
   307→  }
   308→
   309→  function handleDownloadJson() {
   310→    const json = extractJson(output);
   311→    if (!json) return;
   312→    const blob = new Blob([json], { type: 'application/json' });
   313→    const url = URL.createObjectURL(blob);
   314→    const a = document.createElement('a');
   315→    a.href = url;
   316→    a.download = `${tool.id}.json`;
   317→    a.click();
   318→    URL.revokeObjectURL(url);
   319→  }
   320→
   321→  function saveToHistory(queryInputs, queryOutput) {
   322→    if (!tool?.id || !queryOutput) return;
   323→    const entry = { id: Date.now(), timestamp: new Date().toISOString(), inputs: queryInputs, output: queryOutput };
   324→    const key = `gormaran_history_${tool.id}`;
   325→    const existing = (() => { try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch { return []; } })();
   326→    const updated = [entry, ...existing].slice(0, 10);
   327→    localStorage.setItem(key, JSON.stringify(updated));
   328→    setHistory(updated);
   329→    // Persist to Firestore if logged in
   330→    if (currentUser) {
   331→      addDoc(collection(db, 'users', currentUser.uid, 'history'), {
   332→        toolId: tool.id, toolName: tool.name, categoryId,
   333→        inputs: queryInputs, output: queryOutput,
   334→        createdAt: serverTimestamp(),
   335→      }).catch(console.error);
   336→    }
   337→  }
   338→
   339→  async function loadTemplates() {
   340→    try {
   341→      const q = query(
   342→        collection(db, 'users', currentUser.uid, 'templates'),
   343→        where('toolId', '==', tool.id),
   344→        orderBy('createdAt', 'desc')
   345→      );
   346→      const snap = await getDocs(q);
   347→      setTemplates(snap.docs.map(d => ({ id: d.id, ...d.data() })));
   348→    } catch { setTemplates([]); }
   349→  }
   350→
   351→  async function saveTemplate() {
   352→    if (!templateName.trim() || !currentUser) return;
   353→    setSavingTemplate(true);
   354→    try {
   355→      const cleanInputs = Object.fromEntries(
   356→        Object.entries(inputs).filter(([k]) => !k.startsWith('_'))
   357→      );
   358→      const docRef = await addDoc(collection(db, 'users', currentUser.uid, 'templates'), {
   359→        name: templateName.trim(), toolId: tool.id, toolName: tool.name, categoryId,
   360→        inputs: cleanInputs, createdAt: serverTimestamp(),
   361→      });
   362→      setTemplates(prev => [{ id: docRef.id, name: templateName.trim(), inputs: cleanInputs }, ...prev]);
   363→      setTemplateName('');
   364→      setShowSaveTemplate(false);
   365→    } catch (e) { console.error(e); }
   366→    finally { setSavingTemplate(false); }
   367→  }
   368→
   369→  async function deleteTemplate(templateId) {
   370→    try {
   371→      await deleteDoc(doc(db, 'users', currentUser.uid, 'templates', templateId));
   372→      setTemplates(prev => prev.filter(t => t.id !== templateId));
   373→    } catch (e) { console.error(e); }
   374→  }
   375→
   376→  if (!tool) {
   377→    return (
   378→      <div className="ai-tool__empty">
   379→        <div className="ai-tool__empty-icon">⬅️</div>
   380→        <h3>{t('ui.selectTool', { defaultValue: 'Select a tool to get started' })}</h3>
   381→        <p>{t('ui.selectToolSub', { defaultValue: 'Choose a tool from the sidebar to generate AI-powered content' })}</p>
   382→      </div>
   383→    );
   384→  }
   385→
   386→  const toolName = t(`tool.${tool.id}.name`, { defaultValue: tool.name });
   387→  const toolDesc = t(`tool.${tool.id}.desc`, { defaultValue: tool.description });
   388→
   389→  return (
   390→    <div className="ai-tool">
   391→      {/* Header */}
   392→      <div className="ai-tool__header">
   393→        <div className="ai-tool__title-row">
   394→          <span className="ai-tool__icon">{tool.icon}</span>
   395→          <div>
   396→            <h2 className="ai-tool__title">{toolName}</h2>
   397→            <p className="ai-tool__description">{toolDesc}</p>
   398→          </div>
   399→        </div>
   400→      </div>
   401→
   402→      {/* Upgrade notice */}
   403→      {!canUseSpecificTool(categoryId, tool.id) && (
   404→        <div className="ai-tool__upgrade">
   405→          <div className="ai-tool__upgrade-icon">🔒</div>
   406→          <div>
   407→            <strong>{t('ui.proFeature', { defaultValue: 'Pro feature' })}</strong>
   408→            <p>{t('ui.proOnlyText', { defaultValue: 'This tool is available on Grow plan and above.' })}</p>
   409→          </div>
   410→          <Link to="/pricing" className="btn btn-primary btn-sm">{t('ui.upgradeNow', { defaultValue: 'Upgrade Now' })}</Link>
   411→        </div>
   412→      )}
   413→
   414→      <div className="ai-tool__layout">
   415→        {/* Input Panel */}
   416→        <div className="ai-tool__panel ai-tool__input-panel">
   417→          <h3 className="ai-tool__panel-title">{t('ui.yourInputs', { defaultValue: '📝 Your Inputs' })}</h3>
   418→          <form onSubmit={handleGenerate} noValidate>
   419→            {categoryId !== 'creative' && categoryId !== 'strategy' && (
   420→              <div className="ai-tool__biz-context">
   421→                <span className="ai-tool__biz-context-label">🏢 {t('ui.bizContext', { defaultValue: 'Business context' })}</span>
   422→                <FormField
   423→                  field={{ id: '_website_url', label: t('ui.websiteUrl', { defaultValue: 'Website URL' }), type: 'text', placeholder: 'https://tuempresa.com', required: true }}
   424→                  value={inputs._website_url}
   425→                  onChange={handleInputChange}
   426→                  toolId={tool.id}
   427→                />
   428→                <FormField
   429→                  field={{ id: '_location', label: t('ui.location', { defaultValue: 'Location' }), type: 'text', placeholder: 'Vitoria-Gasteiz, Álava. España', required: true }}
   430→                  value={inputs._location}
   431→                  onChange={handleInputChange}
   432→                  toolId={tool.id}
   433→                />
   434→              </div>
   435→            )}
   436→            {/* Templates */}
   437→            {currentUser && templates.length > 0 && (
   438→              <div className="ai-tool__history">
   439→                <button type="button" className="ai-tool__history-toggle" onClick={() => setTemplatesOpen(o => !o)}>
   440→                  <span>⭐</span>
   441→                  <span>{t('ui.myTemplates', { defaultValue: 'My Templates' })} ({templates.length})</span>
   442→                  <span className={`ai-tool__history-arrow ${templatesOpen ? 'open' : ''}`}>▾</span>
   443→                </button>
   444→                {templatesOpen && (
   445→                  <div className="ai-tool__history-list">
   446→                    {templates.map(tpl => (
   447→                      <div key={tpl.id} className="ai-tool__template-row">
   448→                        <button
   449→                          type="button"
   450→                          className="ai-tool__history-item ai-tool__template-item"
   451→                          onClick={() => { setInputs(prev => ({ ...prev, ...tpl.inputs })); setTemplatesOpen(false); }}
   452→                        >
   453→                          <span className="ai-tool__history-preview">⭐ {tpl.name}</span>
   454→                        </button>
   455→                        <button type="button" className="ai-tool__template-delete" onClick={() => deleteTemplate(tpl.id)}>×</button>
   456→                      </div>
   457→                    ))}
   458→                  </div>
   459→                )}
   460→              </div>
   461→            )}
   462→
   463→            {tool.inputs.map((field) => (
   464→              <FormField
   465→                key={field.id}
   466→                field={field}
   467→                value={inputs[field.id]}
   468→                onChange={handleInputChange}
   469→                toolId={tool.id}
   470→              />
   471→            ))}
   472→
   473→            {error && (
   474→              <div className="alert alert-error" style={{ marginBottom: '1rem' }}>
   475→                ⚠️ {error}
   476→              </div>
   477→            )}
   478→
   479→            <div className="ai-tool__actions">
   480→              {isStreaming ? (
   481→                <button type="button" className="btn btn-danger" onClick={handleStop}>
   482→                  ⏹ {t('ui.stopGenerating', { defaultValue: 'Stop Generating' })}
   483→                </button>
   484→              ) : (
   485→                <button
   486→                  type="submit"
   487→                  className="btn btn-primary"
   488→                  disabled={!canUseSpecificTool(categoryId, tool.id)}
   489→                >
   490→                  <span>✨</span>
   491→                  {t('ui.generateWithAI', { defaultValue: 'Generate with AI' })}
   492→                </button>
   493→              )}
   494→              {output && !isStreaming && (
   495→                <button type="button" className="btn btn-ghost btn-sm" onClick={handleClear}>
   496→                  {t('ui.clear', { defaultValue: 'Clear' })}
   497→                </button>
   498→              )}
   499→            </div>
   500→          </form>
   501→        </div>
   502→
   503→        {/* Output Panel */}
   504→        <div className="ai-tool__panel ai-tool__output-panel" ref={outputPanelRef}>
   505→          <div className="ai-tool__output-header">
   506→            <h3 className="ai-tool__panel-title">
   507→              {isGeneratingImage ? (
   508→                <span className="ai-tool__streaming">
   509→                  <span className="ai-tool__streaming-dot" />
   510→                  Generating with DALL·E 3…
   511→                </span>
   512→              ) : isStreaming ? (
   513→                <span className="ai-tool__streaming">
   514→                  <span className="ai-tool__streaming-dot" />
   515→                  {t('ui.aiGenerating', { defaultValue: 'AI is generating...' })}
   516→                </span>
   517→              ) : generatedImage ? (
   518→                `✅ Logo Generated`
   519→              ) : output ? (
   520→                `✅ ${t('ui.aiOutput', { defaultValue: 'AI Output' })}`
   521→              ) : (
   522→                `🤖 ${t('ui.aiOutput', { defaultValue: 'AI Output' })}`
   523→              )}
   524→            </h3>
   525→            {output && !tool.imageOnly && (
   526→              <div className="ai-tool__output-controls">
   527→                <span className="ai-tool__word-count">{wordCount} {t('ui.words', { defaultValue: 'words' })}</span>
   528→                <button
   529→                  className="btn btn-secondary btn-sm"
   530→                  onClick={handleCopy}
   531→                  disabled={isStreaming}
   532→                >
   533→                  {copied ? `✅ ${t('ui.copied', { defaultValue: 'Copied!' })}` : `📋 ${t('ui.copy', { defaultValue: 'Copy' })}`}
   534→                </button>
   535→                {!isStreaming && extractJson(output) && (
   536→                  <button
   537→                    className="btn btn-secondary btn-sm"
   538→                    onClick={handleDownloadJson}
   539→                  >
   540→                    ⬇️ {t('ui.downloadJson', { defaultValue: 'Download JSON' })}
   541→                  </button>
   542→                )}
   543→                {!isStreaming && currentUser && (
   544→                  showSaveTemplate ? (
   545→                    <div className="ai-tool__save-tpl-form">
   546→                      <input
