    14→// Stream AI response using fetch + ReadableStream
    15→export async function streamAIResponse({ categoryId, toolId, inputs, onChunk, onDone, onError, signal }) {
    16→  try {
    17→    const authHeaders = await getAuthHeader();
    18→    const response = await fetch(`${API_URL}/api/ai/generate`, {
    19→      method: 'POST',
    20→      headers: {
    21→        'Content-Type': 'application/json',
    22→        ...authHeaders,
    23→      },
    24→      body: JSON.stringify({ categoryId, toolId, inputs }),
    25→      signal,
    26→    });
    27→
    28→    if (!response.ok) {
    29→      const err = await response.json().catch(() => ({ error: 'Request failed' }));
    30→      throw new Error(err.error || `HTTP ${response.status}`);
    31→    }
    32→
    33→    const reader = response.body.getReader();
    34→    const decoder = new TextDecoder();
    35→
    36→    while (true) {
    37→      const { done, value } = await reader.read();
    38→      if (done) break;
    39→
    40→      const chunk = decoder.decode(value, { stream: true });
    41→      const lines = chunk.split('\n');
    42→
    43→      for (const line of lines) {
    44→        if (line.startsWith('data: ')) {
    45→          const data = line.slice(6).trim();
    46→          if (data === '[DONE]') {
    47→            onDone?.();
    48→            return;
    49→          }
    50→          try {
    51→            const parsed = JSON.parse(data);
    52→            if (parsed.text) onChunk(parsed.text);
    53→            if (parsed.error) throw new Error(parsed.error);
    54→          } catch (e) {
    55→            if (e.message !== 'Unexpected end of JSON input') {
    56→              // silently skip malformed chunks
    57→            }
    58→          }
    59→        }
    60→      }
    61→    }
    62→    onDone?.();
    63→  } catch (err) {
    64→    if (err.name === 'AbortError') return; // user stopped — no error shown
    65→    onError?.(err.message || 'Failed to generate response');
    66→  }
    67→}
